// <p className="font-sans text-base font-normal leading-relaxed text-pretty">

// ❌ Class list order does NOT determine the winner — Tailwind's generated order does
<p className="text-red-500 text-blue-500">Blue wins (later in generated CSS)</p>

// ✅ ! modifier forces !important — guaranteed override
<p className="text-red-500 !text-blue-500">Blue wins (explicit)</p>

// ✅ Custom utilities inside @layer — stays flat, no specificity leak
// app/globals.css
// @layer utilities {
//   .text-brand { color: #6366f1; }
// }
<p className="text-brand text-red-500">Brand wins (source order, predictable)</p>

// ❌ @apply outside @layer — escapes the contract, reintroduces cascade bugs
// .card-title { @apply text-xl font-bold; } → now lives outside utilities layer

// Tailwind v4: inject a runtime token via style prop, consume it as a utility
function ThemedCard({ hue }: { hue: number }) {
  return (
    <div
      style={{ '--color-accent': `oklch(0.65 0.2 ${hue})` } as React.CSSProperties}
      className="rounded-xl p-6 bg-[--color-accent] shadow-[0_4px_24px_--color-accent]/40"
    >
      <p className="text-white/80">Scoped token — no CSS-in-JS needed</p>
      <button
        onClick={() =>
          document.documentElement.style.setProperty('--color-accent', `oklch(0.65 0.2 ${hue + 60})`)
        }
        className="mt-4 px-3 py-1 rounded bg-[--color-accent]/20 text-white text-sm"
      >
        Shift hue globally
      </button>
    </div>
  );
}

